root.sql:
select tab_main.* , decode(row_id,1, 'เลขประจำตัวประชาชน (Personal Id)','') AS id_type from ( SELECT sc_mem_m_membership_registered.id_card -- , '103010 เลขประจำตัวประชาชน (Personal Id)' AS id_type , decode(lag(sc_mem_m_membership_registered.id_card,1,null)over( ORDER BY seq_no,sc_lon_m_loan_card.principal_balance DESC) ,sc_mem_m_membership_registered.id_card,1,1) as row_id
-- 'เลขประจำตัวประชาชน (Personal Id)' AS id_type ,trim( sc_mem_m_ucf_prename.prename ) as prename ,trim( sc_mem_m_membership_registered.member_name ) || ' ' || trim( sc_mem_m_membership_registered.member_surname ) as memname ,( CASE WHEN sc_lon_m_rule.loan_group_code = '01' THEN '104020 เงินกู้ฉุกเฉิน' WHEN sc_lon_m_rule.loan_group_code = '02' THEN '104010 เงินกู้สามัญ' ELSE '104030 เงินกู้พิเศษ' END ) AS loan_type ,sc_lon_m_loan_card.loan_contract_no ,to_date(sc_lon_m_contract.begining_of_contract, 'dd/mm/yyyy') AS begining_of_contract , /*ATM สัญญาเก่า ให้หมดในปี สัญญาในปี ให้หมดในอีก 1 ปี ถ้าไม่ใช่ ATM แต่ วันสิ้นสุดเกิน ปี 2050 ให้ใช้ เริ่มสัญญา + 10000 วัน */ ( CASE WHEN sc_lon_m_rule.atm_status = '1' AND sc_lon_m_contract.begining_of_contract < sc_acc_m_account_constant.beginning_of_account THEN to_date(sc_acc_m_account_constant.ending_of_account, 'dd/mm/yyyy') WHEN sc_lon_m_rule.atm_status = '1' AND sc_lon_m_contract.begining_of_contract >= sc_acc_m_account_constant.beginning_of_account THEN to_date(sc_lon_m_contract.begining_of_contract + 365, 'dd/mm/yyyy') WHEN sc_lon_m_rule.atm_status = '0' AND sc_lon_m_contract.ending_of_contract > sc_lon_m_contract.begining_of_contract + 10000 THEN to_date(sc_lon_m_contract.begining_of_contract + 10000, 'dd/mm/yyyy') ELSE to_date(sc_lon_m_contract.ending_of_contract, 'dd/mm/yyyy') END ) AS ending_of_contract , /*งวดเกิน 999 เอา 999 */ ( CASE WHEN sc_lon_m_contract.loan_installment_amount > 999 THEN 999 ELSE sc_lon_m_contract.loan_installment_amount END ) AS loan_installment_amount ,F_LON_GET_INTRATE(sc_lon_m_contract.loan_type, sc_lon_m_contract.begining_of_contract) * 100 AS loan_int_rate ,sc_lon_m_loan_card.principal_balance ,sc_mem_m_ucf_member_type.mem_type_code ,sc_mem_m_ucf_member_type.mem_type_desc FROM sc_lon_m_loan_card ,sc_mem_m_membership_registered ,sc_mem_m_ucf_prename ,sc_lon_m_rule ,sc_lon_m_contract ,sc_acc_m_account_constant ,sc_mem_m_ucf_member_type ,( SELECT sum(1) OVER ( ORDER BY sum_principal_balance DESC ) AS seq_no /*เทียบเท่า comulative sum ถ้าเอา 50 คน ก้อเอา seq_no <= 50 */ ,membership_no ,sum_principal_balance FROM ( SELECT sc_mem_m_membership_registered.membership_no ,sum(sc_lon_m_loan_card.principal_balance) AS sum_principal_balance FROM sc_lon_m_loan_card ,sc_mem_m_membership_registered WHERE sc_lon_m_loan_card.principal_balance > 0 AND sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_card.membership_no GROUP BY sc_mem_m_membership_registered.membership_no ORDER BY sum_principal_balance DESC /*เรียงหนี้รวม จากมากไปหาน้อย*/ ) tab1 ) tab2 WHERE (sc_mem_m_membership_registered.membership_no = sc_lon_m_loan_card.membership_no) AND (sc_mem_m_membership_registered.prename_code = sc_mem_m_ucf_prename.prename_code) AND (sc_lon_m_loan_card.loan_type = sc_lon_m_rule.loan_type) AND (sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract.loan_contract_no) and sc_mem_m_ucf_member_type.mem_type_code = sc_mem_m_membership_registered.mem_type AND ((sc_lon_m_loan_card.principal_balance > 0)) AND sc_lon_m_loan_card.membership_no = tab2.membership_no AND tab2.seq_no <= 50 ORDER BY seq_no ,sc_lon_m_loan_card.principal_balance DESC
) tab_main
